// utils/progress.js — localStorage-based progress tracker
// saveQuizScore now also stores per-question explanations

const KEYS = {
  COMPLETED:   "aptiprep_completed",
  QUIZ_SCORES: "aptiprep_quiz_scores",
};

export function markTopicComplete(slug) {
  const done = getCompletedTopics();
  if (!done.includes(slug)) {
    done.push(slug);
    localStorage.setItem(KEYS.COMPLETED, JSON.stringify(done));
  }
}

export function getCompletedTopics() {
  try { return JSON.parse(localStorage.getItem(KEYS.COMPLETED) || "[]"); }
  catch { return []; }
}

// questions = array of { question, answer, explanation, options }
// answers   = array of chosen letters (parallel to questions)
export function saveQuizScore(topic, score, total, questions = [], answers = []) {
  const scores = getQuizScores();

  const breakdown = questions.map((q, i) => ({
    question:    q.question,
    options:     q.options,
    correct:     q.answer,
    chosen:      answers[i] || null,
    explanation: q.explanation || "",
    isRight:     answers[i] === q.answer,
  }));

  scores.push({
    topic,
    score,
    total,
    date: new Date().toISOString(),
    breakdown,
  });

  localStorage.setItem(KEYS.QUIZ_SCORES, JSON.stringify(scores));
}

export function getQuizScores() {
  try { return JSON.parse(localStorage.getItem(KEYS.QUIZ_SCORES) || "[]"); }
  catch { return []; }
}

export function clearProgress() {
  localStorage.removeItem(KEYS.COMPLETED);
  localStorage.removeItem(KEYS.QUIZ_SCORES);
}
